mapper.select:
select * from public.surf_fc_tab
         where station = #{station} and datatime = #{dataTime} and validdate <= #{endDateTime}
         order by datatime,validdate

select * from public.surf_fc_tab
         where station
               in 
                      #{id}
                  
               and datatime = #{dataTime} 
               and validdate > #{startDateTime} and validdate <= #{endDateTime} 
               order by vti

select station,datatime,validdate,vti,t2 as at, wd10 as wd, ws10 as ws,vis, tcc as n,lcc, tp as rain24 from ${tableName}
         where station = #{station} and datatime = #{dataTime} and validdate <= #{endDateTime}
         order by datatime,validdate

SELECT * FROM public.stations_tab

    
        provinceid in 
                            #{id}
                       
    
    
        and cityid in 
                        #{id}
                   
    
    
        and cntyid in 
                       #{id}

select station,datatime,validdate,vti,at,at_min,at_max,wd,ws,vis,n as tcc,lcc,rain24 from public.surf_fc_tab
         where
         validdate >= #{startValidDate} and validdate <= #{endValidDate}
         and hour = #{hour}
         and station
               in 
                      #{id}
                  
         order by datatime,validdate

select station,datatime,validdate,vti,at,at_min,at_max,wd,ws,vis,n as tcc,lcc,rain24 from public.surf_fc_tab
         where
         validdate >= #{startValidDate} and validdate <= #{endValidDate}
         and hour = #{hour}
         and vti in 
                      #{id}
                  
         and station
               in 
                      #{id}
                  
         order by datatime,validdate

    	select station,datatime,validdate,vti,t2 as at, wd10 as wd, ws10 as ws,vis, tcc, lcc, tp as rain24 from ${tableName}
	             where
	             validdate >= #{startValidDate} and validdate <= #{endValidDate}
	             and hour = #{hour}
	             and station
	                   in 
	                          #{id}
	                      
