select station,datatime,validdate,vti,at,at_min,at_max,wd,ws,vis,n as tcc,lcc,rain24 from public.surf_fc_tab
         where
         vti > #{startVti} and vti <= #{endVti}
         and validdate >= #{startValidDate} and validdate <= #{endValidDate}
         and hour = #{hour}
         and station
               in 
                      #{id}
                  
         order by datatime,validdate

select station,datatime,validdate,vti,at,at_min,at_max,wd,ws,vis,n as tcc,lcc,rain24 from public.surf_fc_tab
         where
         vti in 
